func:
// ======================================================
// NODE: Fronius Werte auswerten
// Zweck:
// - Fronius PowerFlow API auswerten
// - SOC, Hauslast, PV-Leistung und Batterie-Leistung lesen
// - Werte zusätzlich im flow-Speicher ablegen
// - Keine node.warn Ausgaben: Debug nur über Debug-Node
// ======================================================

const data = msg.payload?.Body?.Data;
const site = data?.Site || {};
const inverters = data?.Inverters || {};

// Ersten Inverter suchen
const firstInvKey = Object.keys(inverters)[0];
const inv = firstInvKey ? inverters[firstInvKey] : {};

// Rohwerte aus Fronius API
const soc = Number(inv.SOC);
const batteryMode = inv.Battery_Mode ?? null;

const pPv = Number(site.P_PV ?? 0);
const pLoadRaw = Number(site.P_Load ?? 0);
const pGrid = Number(site.P_Grid ?? 0);
const pAkkuRaw = Number(site.P_Akku ?? 0);

// Fronius P_Load ist häufig negativ für Verbrauch.
// Für unsere Logik wollen wir Hausverbrauch positiv in W.
const houseLoadW = Math.abs(pLoadRaw);

// V5/Victron-Anzeige-Konvention aus unserer PDF:
// Laden positiv, Entladen negativ.
// Fronius P_Akku muss ggf. später geprüft werden.
// Aktuell übernehmen wir den Rohwert separat und berechnen Anzeige konservativ.
const batteryPowerRawW = pAkkuRaw;
const batteryPowerDisplayW = pAkkuRaw;

// Validierung
const socValid = Number.isFinite(soc);
const houseLoadValid = Number.isFinite(houseLoadW);

// In flow-Speicher schreiben
if (socValid) {
    flow.set("soc_percent", soc);
}

if (houseLoadValid) {
    flow.set("house_load_w", houseLoadW);
}

flow.set("pv_power_w", Number.isFinite(pPv) ? pPv : 0);
flow.set("grid_power_w", Number.isFinite(pGrid) ? pGrid : 0);
flow.set("battery_power_raw_w", Number.isFinite(batteryPowerRawW) ? batteryPowerRawW : 0);
flow.set("battery_mode", batteryMode);

// Debug-/Status-Payload
msg.payload = {
    ok: socValid && houseLoadValid,
    source: "fronius_powerflow",
    soc_percent: socValid ? soc : null,
    battery_mode: batteryMode,
    house_load_w: houseLoadValid ? houseLoadW : null,
    pv_power_w: Number.isFinite(pPv) ? pPv : null,
    grid_power_w: Number.isFinite(pGrid) ? pGrid : null,
    battery_power_raw_w: Number.isFinite(batteryPowerRawW) ? batteryPowerRawW : null,
    battery_power_display_w: Number.isFinite(batteryPowerDisplayW) ? batteryPowerDisplayW : null,
    raw: {
        P_Load: pLoadRaw,
        P_Grid: pGrid,
        P_Akku: pAkkuRaw,
        P_PV: pPv
    }
};

return msg;

// ======================================================
// NODE: Verto_HTTP_auswerten
// Zweck:
// - Fronius PowerFlowRealtimeData auswerten
// - P_Grid, P_Load, P_PV, P_Akku und SOC robust extrahieren
// - Werte im flow context speichern
// - KEINE Regelentscheidung hier
// ======================================================

const DEBUG = true;

// ------------------------------------------------------
// Hilfsfunktionen
// ------------------------------------------------------
function asNumber(v) {
    if (v === null || v === undefined) return null;
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function pickNumber(...values) {
    for (const v of values) {
        const n = asNumber(v);
        if (n !== null) return n;
    }
    return null;
}

// ------------------------------------------------------
// Fronius PowerFlow Struktur
// ------------------------------------------------------
const data = msg.payload?.Body?.Data || {};
const site = data.Site || {};
const inverters = data.Inverters || {};

// Meist gibt es nur Inverter "1"
const inv1 =
    inverters["1"] ||
    inverters[1] ||
    Object.values(inverters)[0] ||
    {};

// ------------------------------------------------------
// Werte lesen
// ------------------------------------------------------

// P_Grid:
// typischerweise:
//   > 0 = Netzbezug
//   < 0 = Einspeisung
const gridPowerW = pickNumber(
    site.P_Grid,
    msg.grid_power_w,
    msg.payload?.grid_power_w
);

// P_Load:
// bei Fronius oft negativ, wir speichern Hausverbrauch positiv
const pLoadRaw = pickNumber(
    site.P_Load,
    msg.house_load_w,
    msg.payload?.house_load_w
);

const houseLoadW = pLoadRaw !== null ? Math.abs(pLoadRaw) : null;

const pvPowerW = pickNumber(
    site.P_PV,
    msg.pv_power_w,
    msg.payload?.pv_power_w
);

// P_Akku / P_Battery:
// Vorzeichen kann je nach Fronius-Ansicht unterschiedlich sein.
// Wir speichern erstmal roh und ändern NICHTS blind.
const batteryPowerRawW = pickNumber(
    site.P_Akku,
    site.P_Battery,
    msg.battery_power_raw_w,
    msg.payload?.battery_power_raw_w
);

// SOC kann je nach Endpoint im Inverter-Block oder Site liegen
const socPercent = pickNumber(
    inv1.SOC,
    site.SOC,
    msg.soc_percent,
    msg.payload?.soc_percent
);

// Battery Mode, falls vorhanden
const batteryMode =
    inv1.Battery_Mode ||
    inv1.battery_mode ||
    site.Battery_Mode ||
    msg.battery_mode ||
    msg.payload?.battery_mode ||
    null;

// ------------------------------------------------------
// Plausibilitätscheck
// ------------------------------------------------------
if (gridPowerW === null) {
    node.error("P_Grid / grid_power_w nicht gefunden", msg);
    return null;
}

if (houseLoadW === null) {
    node.warn("P_Load / house_load_w nicht gefunden, Regelung kann später nur mit P_Grid arbeiten");
}

// ------------------------------------------------------
// flow context speichern
// ------------------------------------------------------
flow.set("fronius_grid_power_w", gridPowerW);
flow.set("fronius_house_load_w", houseLoadW);
flow.set("fronius_pv_power_w", pvPowerW);
flow.set("fronius_battery_power_raw_w", batteryPowerRawW);
flow.set("fronius_soc_percent", socPercent);
flow.set("fronius_battery_mode", batteryMode);
flow.set("fronius_http_last_seen", Date.now());

// Für spätere Functions auch auf msg schreiben
msg.ok = true;
msg.source = "fronius_powerflow";

msg.grid_power_w = gridPowerW;
msg.house_load_w = houseLoadW;
msg.pv_power_w = pvPowerW;
msg.battery_power_raw_w = batteryPowerRawW;
msg.soc_percent = socPercent;
msg.battery_mode = batteryMode;

if (DEBUG) {
    msg.debug_fronius = {
        grid_power_w: gridPowerW,
        grid_meaning:
            gridPowerW > 0 ? "Netzbezug" :
            gridPowerW < 0 ? "Einspeisung" :
            "Null",
        house_load_w: houseLoadW,
        pv_power_w: pvPowerW,
        battery_power_raw_w: batteryPowerRawW,
        soc_percent: socPercent,
        battery_mode: batteryMode,
        last_seen: new Date().toISOString()
    };
}

return msg;

// ======================================================
// NODE: Forecast_auswerten_V6
// Zweck:
// - forecast.solar Response auswerten
// - result.watt_hours_period pro Europe/Vienna-Kalendertag summieren
// - heute, morgen, übermorgen in kWh berechnen
// - Werte im flow-Speicher ablegen
// - V6: noch keine finale Steuerentscheidung, nur Forecast-Daten
// ======================================================

function viennaDateString(offsetDays = 0) {
    const fmt = new Intl.DateTimeFormat("sv-SE", {
        timeZone: "Europe/Vienna",
        year: "numeric",
        month: "2-digit",
        day: "2-digit"
    });

    const now = new Date();
    const todayStr = fmt.format(now);

    // Mittagszeit verhindert DST-/Zeitzonen-Kantenprobleme
    const base = new Date(`${todayStr}T12:00:00`);
    base.setDate(base.getDate() + offsetDays);

    return fmt.format(base);
}

function round1(x) {
    return Math.round(x * 10) / 10;
}

function sumWhForDate(wattHoursPeriod, dateStr) {
    let sumWh = 0;
    let points = 0;

    for (const [ts, whRaw] of Object.entries(wattHoursPeriod || {})) {
        if (!ts.startsWith(dateStr)) continue;

        const wh = Number(whRaw);
        if (!Number.isFinite(wh)) continue;

        sumWh += wh;
        points++;
    }

    return {
        kwh: round1(sumWh / 1000),
        points
    };
}

// Payload robust behandeln
let payload = msg.payload;

if (typeof payload === "string") {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        payload = {};
    }
}

const whPeriod = payload?.result?.watt_hours_period;

const todayDate = viennaDateString(0);
const tomorrowDate = viennaDateString(1);
const dayAfterTomorrowDate = viennaDateString(2);

let source = "forecast.solar/watt_hours_period";
let usedFallback = false;

let today = { kwh: 0, points: 0 };
let tomorrow = { kwh: 0, points: 0 };
let dayAfterTomorrow = { kwh: 0, points: 0 };

if (whPeriod && typeof whPeriod === "object") {
    today = sumWhForDate(whPeriod, todayDate);
    tomorrow = sumWhForDate(whPeriod, tomorrowDate);
    dayAfterTomorrow = sumWhForDate(whPeriod, dayAfterTomorrowDate);

    if (today.points + tomorrow.points + dayAfterTomorrow.points === 0) {
        usedFallback = true;
        source = "fallback_no_matching_dates";
    }
} else {
    usedFallback = true;
    source = "fallback_missing_watt_hours_period";
}

// Flow-Speicher für Strategie_V6
flow.set("forecast_today_kwh", today.kwh);
flow.set("forecast_tomorrow_kwh", tomorrow.kwh);
flow.set("forecast_day_after_tomorrow_kwh", dayAfterTomorrow.kwh);

flow.set("forecast_today_date", todayDate);
flow.set("forecast_tomorrow_date", tomorrowDate);
flow.set("forecast_day_after_tomorrow_date", dayAfterTomorrowDate);

flow.set("forecast_source", source);
flow.set("forecast_used_fallback", usedFallback);
flow.set("forecast_updated_at", new Date().toISOString());

// Abwärtskompatibel für alte Nodes
flow.set("forecast_kwh", today.kwh);
flow.set("forecast_date", todayDate);

// Debug-Ausgabe
msg.payload = {
    ok: !usedFallback,
    source,
    used_fallback: usedFallback,
    forecast: {
        today: {
            date: todayDate,
            kwh: today.kwh,
            points: today.points
        },
        tomorrow: {
            date: tomorrowDate,
            kwh: tomorrow.kwh,
            points: tomorrow.points
        },
        day_after_tomorrow: {
            date: dayAfterTomorrowDate,
            kwh: dayAfterTomorrow.kwh,
            points: dayAfterTomorrow.points
        }
    }
};

return msg;

// ======================================================
// NODE: Strategie_V6_Debug
// Zweck:
// - V6 Strategieentscheidung nur als Debug berechnen
// - Eigenverbrauch hat oberste Priorität
// - Forecast heute + morgen bewerten
// - Winter-/Reserve-Logik berücksichtigen
// - Ladeblockade bis 10:30 vorbereiten
// - Entladung morgens vorbereiten
// - Noch KEIN Modbus-Schreiben
// ======================================================

// ===============================
// KONFIGURATION
// ===============================

// OutWRte / InWRte bleiben prozentbasiert:
// 0     = 0 %
// 10000 = 100 %
const OUTWRTE_MAX = 10000;

// Bezugsleistung nur zur Umrechnung Hauslast -> OutWRte.
// Keine Speicher-kWh-Logik, damit spätere Speichererweiterung möglich bleibt.
const BATTERY_POWER_REF_W = 16600;

// Zeitfenster Europe/Vienna
const DISCHARGE_START_MIN = 4 * 60 + 30;   // 04:30
const DISCHARGE_END_MIN   = 8 * 60;        // 08:00

const CHARGE_BLOCK_START_MIN = 6 * 60;     // 06:00
const CHARGE_BLOCK_END_MIN   = 10 * 60 + 30; // 10:30

// Sicherheitsabstände
const SOC_MARGIN_FOR_ACTION = 5;   // Aktion nur wenn SOC mindestens min_soc + 5 %
const CHARGE_BLOCK_MARGIN = 10;    // Ladeblockade nur wenn SOC mindestens min_soc + 10 %

// ===============================
// HILFSFUNKTIONEN
// ===============================

function clamp(num, min, max) {
    return Math.min(Math.max(num, min), max);
}

function round1(x) {
    return Math.round(x * 10) / 10;
}

function getViennaMinutes() {
    const timeString = new Intl.DateTimeFormat("sv-SE", {
        timeZone: "Europe/Vienna",
        hour: "2-digit",
        minute: "2-digit",
        hour12: false
    }).format(new Date());

    const [h, m] = timeString.split(":").map(Number);
    return h * 60 + m;
}

function getViennaDateTimeString() {
    return new Intl.DateTimeFormat("sv-SE", {
        timeZone: "Europe/Vienna",
        year: "numeric",
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false
    }).format(new Date()).replace(" ", "T");
}

// ===============================
// FLOW-WERTE EINLESEN
// ===============================

const todayKwh = Number(flow.get("forecast_today_kwh") ?? 0);
const tomorrowKwh = Number(flow.get("forecast_tomorrow_kwh") ?? 0);

const todayDate = flow.get("forecast_today_date") ?? null;
const tomorrowDate = flow.get("forecast_tomorrow_date") ?? null;
const forecastSource = flow.get("forecast_source") ?? "unknown";
const forecastUsedFallback = Boolean(flow.get("forecast_used_fallback"));

const soc = Number(flow.get("soc_percent"));
const houseLoadW = Number(flow.get("house_load_w") ?? 0);
const pvPowerW = Number(flow.get("pv_power_w") ?? 0);
const gridPowerW = Number(flow.get("grid_power_w") ?? 0);
const batteryMode = flow.get("battery_mode") ?? null;

// ===============================
// VALIDIERUNG
// ===============================

const socValid = Number.isFinite(soc);
const forecastValid =
    Number.isFinite(todayKwh) &&
    Number.isFinite(tomorrowKwh) &&
    !forecastUsedFallback;

const houseLoadValid = Number.isFinite(houseLoadW);

const nowMinutes = getViennaMinutes();

const inDischargeWindow =
    nowMinutes >= DISCHARGE_START_MIN &&
    nowMinutes < DISCHARGE_END_MIN;

const inChargeBlockWindow =
    nowMinutes >= CHARGE_BLOCK_START_MIN &&
    nowMinutes < CHARGE_BLOCK_END_MIN;

// ===============================
// RESERVEKLASSE AUS HEUTE + MORGEN
// ===============================

// Grundidee:
// - Eigenverbrauch bleibt oberstes Ziel
// - Wenn morgen schlecht ist, Akku stärker schonen
// - Wenn heute und morgen gut sind, Direktverkauf/Ladeblockade eher erlauben

let reserveClass = "unknown";
let minSoc = 80;
let reserveReason = "forecast_invalid_or_missing";

if (forecastValid) {
    if (tomorrowKwh < 25) {
        reserveClass = "HIGH";
        minSoc = 75;
        reserveReason = "tomorrow_bad_keep_battery_for_self_consumption";
    } else if (tomorrowKwh < 35) {
        reserveClass = "MEDIUM_HIGH";
        minSoc = 50;
        reserveReason = "tomorrow_weak_keep_more_reserve";
    } else if (tomorrowKwh < 40) {
        reserveClass = "NORMAL";
        minSoc = 35;
        reserveReason = "tomorrow_medium_normal_reserve";
    } else {
        reserveClass = "LOW";
        minSoc = 15;
        reserveReason = "today_and_tomorrow_good_lower_reserve_ok";
    }

    // Wenn heute schlecht ist, zusätzlich vorsichtiger sein
    if (todayKwh < 40) {
        minSoc = Math.max(minSoc, 65);
        reserveClass = reserveClass === "LOW" ? "NORMAL" : reserveClass;
        reserveReason = "today_weak_raise_reserve";
    }
}

// ===============================
// HAUSLAST IN OUTWRTE UMRECHNEN
// ===============================

let houseLoadOutwrte = 0;

if (houseLoadValid && houseLoadW > 0) {
    houseLoadOutwrte = Math.ceil((houseLoadW / BATTERY_POWER_REF_W) * OUTWRTE_MAX) + 100;
    houseLoadOutwrte = clamp(houseLoadOutwrte, 0, OUTWRTE_MAX);
}

// ===============================
// BASIS-ENTLADESTRATEGIE MORGENS
// ===============================

let baseOutwrte = 0;
let dischargeCase = "none";

// Heute entscheidet primär, morgen bestimmt Reserve/Aggressivität
if (forecastValid) {
    if (todayKwh >= 80 && tomorrowKwh >= 60) {
        baseOutwrte = 10000;
        dischargeCase = "today_very_good_tomorrow_good";
    } else if (todayKwh >= 80 && tomorrowKwh >= 40) {
        baseOutwrte = 7000;
        dischargeCase = "today_very_good_tomorrow_medium";
    } else if (todayKwh >= 60 && tomorrowKwh >= 60) {
        baseOutwrte = 5000;
        dischargeCase = "today_good_tomorrow_good";
    } else if (todayKwh >= 60 && tomorrowKwh >= 40) {
        baseOutwrte = 3500;
        dischargeCase = "today_good_tomorrow_medium";
    } else if (todayKwh >= 40 && tomorrowKwh >= 60) {
        baseOutwrte = 3000;
        dischargeCase = "today_medium_tomorrow_good";
    } else if (todayKwh >= 40 && tomorrowKwh >= 40) {
        baseOutwrte = 2000;
        dischargeCase = "today_medium_tomorrow_medium";
    } else {
        baseOutwrte = 0;
        dischargeCase = "forecast_not_enough_for_pre_discharge";
    }
}

// Finaler OutWRte berücksichtigt Eigenverbrauch
let finalOutwrte = 0;
if (baseOutwrte > 0) {
    finalOutwrte = Math.max(baseOutwrte, houseLoadOutwrte);
    finalOutwrte = clamp(finalOutwrte, 0, OUTWRTE_MAX);
}

// ===============================
// ENTLADE-ERLAUBNIS
// ===============================

let dischargeAllowed = false;
let dischargeReason = "not_evaluated";

if (!forecastValid) {
    dischargeReason = "forecast_invalid_no_discharge";
} else if (!socValid) {
    dischargeReason = "soc_missing_no_discharge";
} else if (!inDischargeWindow) {
    dischargeReason = "outside_discharge_window";
} else if (soc <= minSoc + SOC_MARGIN_FOR_ACTION) {
    dischargeReason = "soc_too_low_self_consumption_priority";
} else if (baseOutwrte <= 0) {
    dischargeReason = "forecast_not_strong_enough_for_discharge";
} else if (reserveClass === "HIGH") {
    dischargeReason = "reserve_high_no_discharge";
} else {
    dischargeAllowed = true;
    dischargeReason = "inside_window_soc_ok_forecast_ok";
}

// ===============================
// LADEBLOCKADE BIS 10:30
// ===============================

// Ziel:
// Bei guter Prognose und ausreichendem SOC vormittags nicht sofort laden,
// sondern PV eher direkt ins Netz / Energiegemeinschaft schicken.
//
// Aber:
// Bei niedrigem SOC oder schwachem Folgetag keine Ladeblockade.
// Eigenverbrauch bleibt oberste Priorität.

let chargeBlockAllowed = false;
let chargeBlockReason = "not_evaluated";

// Vorerst harte, konservative Logik:
if (!forecastValid) {
    chargeBlockReason = "forecast_invalid_no_charge_block";
} else if (!socValid) {
    chargeBlockReason = "soc_missing_no_charge_block";
} else if (!inChargeBlockWindow) {
    chargeBlockReason = "outside_charge_block_window";
} else if (reserveClass === "HIGH") {
    chargeBlockReason = "reserve_high_keep_charging_allowed";
} else if (todayKwh < 60) {
    chargeBlockReason = "today_forecast_too_low_no_charge_block";
} else if (tomorrowKwh < 40) {
    chargeBlockReason = "tomorrow_too_weak_no_charge_block";
} else if (soc <= minSoc + CHARGE_BLOCK_MARGIN) {
    chargeBlockReason = "soc_too_low_no_charge_block_self_consumption_priority";
} else {
    chargeBlockAllowed = true;
    chargeBlockReason = "good_forecast_soc_ok_direct_export_preferred_until_1030";
}

// ===============================
// MODBUS-VORSCHLAG, NOCH NICHT SCHREIBEN
// ===============================

// Fronius Basic Storage Control:
// 0 = externe Steuerung aus
// 1 = Ladelimit aktiv
// 2 = Entladelimit aktiv
// 3 = Lade- und Entladelimit aktiv

let storctlModProposed = 0;
let outwrteProposed = 0;
let inwrteProposed = null;

// Nur Vorschlag, noch kein Write!
if (dischargeAllowed && chargeBlockAllowed) {
    storctlModProposed = 3;
    outwrteProposed = finalOutwrte;
    inwrteProposed = 0;
} else if (dischargeAllowed) {
    storctlModProposed = 2;
    outwrteProposed = finalOutwrte;
    inwrteProposed = null;
} else if (chargeBlockAllowed) {
    storctlModProposed = 1;
    outwrteProposed = 0;
    inwrteProposed = 0;
} else {
    storctlModProposed = 0;
    outwrteProposed = 0;
    inwrteProposed = null;
}

// ===============================
// FLOW SPEICHERN FÜR SPÄTERE WRITE-NODES
// ===============================

flow.set("strategy_v6_reserve_class", reserveClass);
flow.set("strategy_v6_min_soc", minSoc);
flow.set("strategy_v6_discharge_allowed", dischargeAllowed);
flow.set("strategy_v6_charge_block_allowed", chargeBlockAllowed);
flow.set("strategy_v6_storctl_mod_proposed", storctlModProposed);
flow.set("strategy_v6_outwrte_proposed", outwrteProposed);
flow.set("strategy_v6_inwrte_proposed", inwrteProposed);

// Alte Namen für spätere Kompatibilität
flow.set("storctl_mod", storctlModProposed);
flow.set("outwrte", outwrteProposed);
flow.set("inwrte", inwrteProposed);

// ===============================
// DEBUG PAYLOAD
// ===============================

msg.payload = {
    ok: forecastValid && socValid,

    mode: "debug_only_no_modbus_write",

    time: {
        vienna_now: getViennaDateTimeString(),
        minutes: nowMinutes,
        in_discharge_window: inDischargeWindow,
        discharge_window: "04:30-08:00",
        in_charge_block_window: inChargeBlockWindow,
        charge_block_window: "06:00-10:30"
    },

    inputs: {
        forecast_today_date: todayDate,
        forecast_today_kwh: round1(todayKwh),
        forecast_tomorrow_date: tomorrowDate,
        forecast_tomorrow_kwh: round1(tomorrowKwh),
        forecast_source: forecastSource,
        forecast_used_fallback: forecastUsedFallback,

        soc_percent: socValid ? round1(soc) : null,
        house_load_w: houseLoadValid ? Math.round(houseLoadW) : null,
        pv_power_w: Number.isFinite(pvPowerW) ? Math.round(pvPowerW) : null,
        grid_power_w: Number.isFinite(gridPowerW) ? Math.round(gridPowerW) : null,
        battery_mode: batteryMode
    },

    reserve: {
        reserve_class: reserveClass,
        min_soc: minSoc,
        reason: reserveReason
    },

    discharge: {
        allowed: dischargeAllowed,
        reason: dischargeReason,
        case: dischargeCase,
        base_outwrte: baseOutwrte,
        house_load_outwrte: houseLoadOutwrte,
        final_outwrte: finalOutwrte
    },

    charge_block: {
        allowed: chargeBlockAllowed,
        reason: chargeBlockReason,
        inwrte: chargeBlockAllowed ? 0 : null,
        until: "10:30"
    },

    modbus_proposal: {
        write_active: false,
        storctl_mod: storctlModProposed,
        outwrte: outwrteProposed,
        inwrte: inwrteProposed,
        note: "Nur Vorschlag. Noch nicht mit Modbus Write verbinden."
    }
};

return msg;
